<script>
$(function(){function qs(){return $('#form_lrq').serialize();}function loadReport(){$('#lrq_alert').hide().text('');$('#lrq_result').html('<div class="text-center" style="padding:30px"><i class="fa fa-spinner fa-spin fa-2x"></i><br>Loading...</div>');$('#btn_filter').prop('disabled',true);$.ajax({url:'<?=base_admin();?>modul/finance_report/finance_report_laba_rugi_kuartal_action.php?act=filter',type:'POST',dataType:'json',data:qs()}).done(function(res){if(res.status==='success')$('#lrq_result').html(res.html);else{$('#lrq_result').html('<div class="alert alert-danger">'+(res.message||'Laporan gagal diproses.')+'</div>');$('#lrq_alert').text(res.message||'Laporan gagal diproses.').show();}}).fail(function(xhr){$('#lrq_result').html('<div class="alert alert-danger">Server error</div>');$('#lrq_alert').text(xhr.responseText||'Server error').show();}).always(function(){$('#btn_filter').prop('disabled',false);});}
$('#form_lrq').on('submit',function(e){e.preventDefault();loadReport();});$('#btn_excel').on('click',function(){window.location='<?=base_admin();?>modul/finance_report/finance_report_laba_rugi_kuartal_action.php?act=excel&'+qs();});$('#btn_print').on('click',function(){window.open('<?=base_admin();?>modul/finance_report/finance_report_laba_rugi_kuartal_action.php?act=print&'+qs(),'_blank');});loadReport();});
</script>
